# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify, render_template_string
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)

# Dummy database to store user emails and reset tokens
users_db = {}

@app.route('/request_reset', methods=['POST'])
def request_password_reset():
    email = request.json.get('email')
    
    if email not in users_db:
        return jsonify({'error': 'Email not found'}), 404
    
    token = secrets.token_urlsafe()
    users_db[email] = token
    
    reset_link = f"http://example.com/reset?token={token}"
    
    send_reset_email(email, reset_link)
    
    return jsonify({'message': 'Reset link sent'})

def send_reset_email(email, reset_link):
    msg = MIMEText(f'Click the following link to reset your password: {reset_link}')
    msg['Subject'] = 'Password Reset Request'
    msg['From'] = 'your-email@example.com'
    msg['To'] = email
    
    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login('your-email@example.com', 'your-password')
        server.sendmail('your-email@example.com', email, msg.as_string())

if __name__ == '__main__':
    app.run(debug=True)